/**
 * Simple Anthropic Messages API client.
 *
 * For one-shot LLM calls (classification, generation, extraction) where
 * a full Claude Code session is overkill. Respects the AI proxy config
 * (ANTHROPIC_BASE_URL / ANTHROPIC_API_KEY) so it works in both local-dev
 * and production environments.
 *
 * Lifted into `@shogo-ai/agent` from `@shogo/shared-runtime` (was AGPL)
 * under MIT. The original `@shogo/shared-runtime/ai-client` re-exports
 * this module unchanged for backwards compatibility.
 */
interface Message {
    role: 'user' | 'assistant';
    content: string;
}
interface SendMessageOptions {
    /** Model to use. Defaults to claude-sonnet-4-5-20250514 */
    model?: string;
    /** System prompt */
    system?: string;
    /** Max tokens to generate. Defaults to the model's max from the catalog. */
    maxTokens?: number;
    /** Temperature. Defaults to 0 */
    temperature?: number;
    /** Explicit API key (overrides env) */
    apiKey?: string;
    /** Explicit base URL (overrides env) */
    baseUrl?: string;
}
interface MessageResponse {
    text: string;
    inputTokens: number;
    outputTokens: number;
    stopReason: string;
}
/**
 * Send a single message to Claude and get the full text response.
 *
 * ```ts
 * const { text } = await sendMessage('Summarize this in 3 bullets: ...')
 * ```
 */
declare function sendMessage(prompt: string, options?: SendMessageOptions): Promise<MessageResponse>;
/**
 * Send a multi-turn conversation to Claude and get the full text response.
 */
declare function sendMessages(messages: Message[], options?: SendMessageOptions): Promise<MessageResponse>;
/**
 * Send a message and parse the response as JSON.
 * Strips markdown code fences if present.
 *
 * ```ts
 * const data = await sendMessageJSON<{ items: string[] }>(
 *   'List 5 colors as JSON: { "items": [...] }'
 * )
 * ```
 */
declare function sendMessageJSON<T = unknown>(prompt: string, options?: SendMessageOptions): Promise<{
    data: T;
    usage: {
        inputTokens: number;
        outputTokens: number;
    };
}>;

export { type Message, type MessageResponse, type SendMessageOptions, sendMessage, sendMessageJSON, sendMessages };
